CREATE TABLE IF NOT EXISTS sup_quality_issue (
 quality_issue_id bigint NOT NULL,issue_no varchar(64) NOT NULL,supplier_id bigint NOT NULL,source_type varchar(32) NOT NULL,source_no varchar(64) NULL,issue_type varchar(32) NOT NULL,severity smallint NOT NULL,issue_description varchar(1024) NOT NULL,issue_status smallint NOT NULL COMMENT '1待处理 2整改中 3待审核 4已关闭 5已逾期',rectification_deadline datetime(3) NULL,rectification_plan text NULL,verification_comment varchar(512) NULL,created_by bigint NOT NULL,created_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3),updated_by bigint NULL,updated_at datetime(3) NOT NULL DEFAULT CURRENT_TIMESTAMP(3) ON UPDATE CURRENT_TIMESTAMP(3),version int NOT NULL DEFAULT 0,deleted tinyint NOT NULL DEFAULT 0,PRIMARY KEY(quality_issue_id),UNIQUE KEY uk_sup_quality_issue_no(issue_no),KEY idx_sup_quality_supplier_status(supplier_id,issue_status,rectification_deadline),KEY idx_sup_quality_source(source_type,source_no)
) ENGINE=InnoDB DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci COMMENT='供应商质量问题聚合';
